// Kafka Producer Service
@Service
class EventProducerService {

    private static final String DEFAULT_TOPIC = "event-tracking";
    private static final Set<String> ALLOWED_HTTP_HEADERS = Set.of(
            "tracking-id", "user-id", "correlation-id", "session-id",
            "x-request-id", "x-trace-id", "x-source", "x-event-type"
    );

    private final KafkaTemplate<String, String> kafkaTemplate;

    public EventProducerService(KafkaTemplate<String, String> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public CompletableFuture<SendResult<String, String>> sendEvent(
            EventRequest eventRequest,
            Map<String, String> httpHeaders) {

        String topic = eventRequest.getTopic() != null ? eventRequest.getTopic() : DEFAULT_TOPIC;
        String key = eventRequest.getKey();
        String payload = eventRequest.getPayload();

        ProducerRecord<String, String> record = new ProducerRecord<>(topic, key, payload);

        // Add HTTP headers that match allowed prefixes/names
        if (httpHeaders != null) {
            httpHeaders.forEach((headerKey, headerValue) -> {
                String normalizedKey = headerKey.toLowerCase();
                if (ALLOWED_HTTP_HEADERS.contains(normalizedKey) || normalizedKey.startsWith("x-custom-")) {
                    record.headers().add(normalizedKey, headerValue.getBytes(StandardCharsets.UTF_8));
                }
            });
        }

        // Add custom headers from request body
        if (eventRequest.getCustomHeaders() != null) {
            eventRequest.getCustomHeaders().forEach((headerKey, headerValue) -> {
                if (headerKey != null && headerValue != null) {
                    record.headers().add(headerKey, headerValue.getBytes(StandardCharsets.UTF_8));
                }
            });
        }

        // Add system-generated metadata headers
        record.headers().add("produced-timestamp",
                String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8));
        record.headers().add("producer-app", "event-tracking-service".getBytes(StandardCharsets.UTF_8));

        return kafkaTemplate.send(record).toCompletableFuture();
    }

    public Map<String, String> extractAppliedHeaders(ProducerRecord<String, String> record) {
        Map<String, String> headerMap = new LinkedHashMap<>();
        record.headers().forEach(header ->
                headerMap.put(header.key(), new String(header.value(), StandardCharsets.UTF_8))
        );
        return headerMap;
    }
}

// REST Controller
@RestController
@RequestMapping("/api/v1/events")
class EventController {

    private final EventProducerService eventProducerService;

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping("/publish")
    public ResponseEntity<EventResponse> publishEvent(
            @RequestBody EventRequest eventRequest,
            @RequestHeader(value = "tracking-id", required = false) String trackingId,
            @RequestHeader(value = "user-id", required = false) String userId,
            @RequestHeader(value = "correlation-id", required = false) String correlationId,
            @RequestHeader(value = "session-id", required = false) String sessionId,
            @RequestHeader(value = "x-request-id", required = false) String requestId,
            @RequestHeader(value = "x-trace-id", required = false) String traceId,
            @RequestHeader(value = "x-source", required = false) String source,
            @RequestHeader(value = "x-event-type", required = false) String eventType,
            @RequestHeader Map<String, String> allHeaders) {

        if (eventRequest.getPayload() == null || eventRequest.getPayload().isBlank()) {
            EventResponse errorResponse = new EventResponse();
            errorResponse.setStatus("ERROR");
            errorResponse.setMessage("Payload cannot be null or empty");
            return ResponseEntity.badRequest().body(errorResponse);
        }

        try {
            CompletableFuture<SendResult<String, String>> future =
                    eventProducerService.sendEvent(eventRequest, allHeaders);

            SendResult<String, String> result = future.get();

            EventResponse response = new EventResponse();
            response.setStatus("SUCCESS");
            response.setMessage("Event published successfully");
            response.setTopic(result.getRecordMetadata().topic());
            response.setPartition(result.getRecordMetadata().partition());
            response.setOffset(result.getRecordMetadata().offset());

            // Collect all applied headers for response
            Map<String, String> appliedHeaders = new LinkedHashMap<>();
            result.getProducerRecord().headers().forEach(header ->
                    appliedHeaders.put(header.key(), new String(header.value(), StandardCharsets.UTF_8))
            );
            response.setHeadersApplied(appliedHeaders);

            return ResponseEntity.ok(response);

        } catch (Exception e) {
            EventResponse errorResponse = new EventResponse();
            errorResponse.setStatus("ERROR");
            errorResponse.setMessage("Failed to publish event: " + e.getMessage());
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(errorResponse);
        }
    }

    @PostMapping("/publish/batch")
    public ResponseEntity<List<EventResponse>> publishBatchEvents(
            @RequestBody List<EventRequest> eventRequests,
            @RequestHeader Map<String, String> allHeaders) {

        List<EventResponse> responses = new ArrayList<>();

        for (EventRequest eventRequest : eventRequests) {
            try {
                CompletableFuture<SendResult<String, String>> future =
                        eventProducerService.sendEvent(eventRequest, allHeaders);

                SendResult<String, String> result = future.get();

                EventResponse response = new EventResponse();
                response.setStatus("SUCCESS");
                response.setMessage("Event published successfully");
                response.setTopic(result.getRecordMetadata().topic());
                response.setPartition(result.getRecordMetadata().partition());
                response.setOffset(result.getRecordMetadata().offset());

                Map<String, String> appliedHeaders = new LinkedHashMap<>();
                result.getProducerRecord().headers().forEach(header ->
                        appliedHeaders.put(header.key(), new String(header.value(), StandardCharsets.UTF_8))
                );
                response.setHeadersApplied(appliedHeaders);

                responses.add(response);

            } catch (Exception e) {
                EventResponse errorResponse = new EventResponse();
                errorResponse.setStatus("ERROR");
                errorResponse.setMessage("Failed to publish event: " + e.getMessage());
                responses.add(errorResponse);
            }
        }

        boolean anyError = responses.stream().anyMatch(r -> "ERROR".equals(r.getStatus()));
        HttpStatus status = anyError ? HttpStatus.MULTI_STATUS : HttpStatus.OK;
        return ResponseEntity.status(status).body(responses);
    }

    @GetMapping("/health")
    public ResponseEntity<Map<String, String>> health() {
        Map<String, String> status = new HashMap<>();
        status.put("status", "UP");
        status.put("service", "event-tracking-producer");
        return ResponseEntity.ok(status);
    }
}